import React, { useEffect, useCallback } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { fetchFeedPosts } from '../redux/thunks/postThunks';
import PostCard from '../components/posts/PostCard';
import './Home.css';

const Home = () => {
  const { user } = useSelector((state) => state.auth);
  const { feedPosts, feedLoading, hasMoreFeed } = useSelector((state) => state.posts);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  useEffect(() => {
    dispatch(fetchFeedPosts({ skip: 0, limit: 20 }));
  }, [dispatch]);

  const handleLoadMore = useCallback(() => {
    if (!feedLoading && hasMoreFeed) {
      dispatch(fetchFeedPosts({ skip: feedPosts.length, limit: 20 }));
    }
  }, [dispatch, feedLoading, hasMoreFeed, feedPosts.length]);

  const handleRefresh = () => {
    dispatch(fetchFeedPosts({ skip: 0, limit: 20 }));
  };

  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return 'Good morning';
    if (hour < 18) return 'Good afternoon';
    return 'Good evening';
  };

  const quickActions = [
    { label: 'Friends', icon: '👥', path: '/friends' },
    { label: 'Messages', icon: '💬', path: '/messages' },
    { label: 'Find Friends', icon: '🔍', path: '/search' },
    { label: 'Refresh', icon: '🔄', action: handleRefresh },
  ];

  return (
    <div className="home-page">
      <div className="home-greeting">
        <h2>{getGreeting()}, {user?.firstName || 'Friend'}!</h2>
        <p>Welcome to FriendLinq</p>
      </div>

      <div className="home-quick-actions">
        {quickActions.map((action, i) => (
          <button
            key={i}
            className="home-quick-card"
            onClick={() => action.path ? navigate(action.path) : action.action?.()}
          >
            <span className="home-quick-icon">{action.icon}</span>
            <span className="home-quick-label">{action.label}</span>
          </button>
        ))}
      </div>

      <div className="home-feed">
        {feedPosts.length === 0 && !feedLoading && (
          <div className="home-feed-empty">
            <p>📰 No posts yet</p>
            <p className="home-feed-empty-sub">Add friends to see their posts here</p>
          </div>
        )}

        {feedPosts.map((post) => (
          <PostCard key={post._id} post={post} />
        ))}

        {hasMoreFeed && feedPosts.length > 0 && (
          <button
            className="home-load-more"
            onClick={handleLoadMore}
            disabled={feedLoading}
          >
            {feedLoading ? 'Loading...' : 'Load More Posts'}
          </button>
        )}

        {feedLoading && feedPosts.length === 0 && (
          <div className="home-feed-loading">
            <div className="page-loading-spinner" />
          </div>
        )}
      </div>
    </div>
  );
};

export default Home;
